const body = $input.first().json.body || $input.first().json;
const db06_id = (body.db06_id || body.id || '').toString().replace(/-/g, '');
if (!db06_id) throw new Error('missing db06_id');
return [{ json: { db06_id } }];

const p = $input.first().json;
return [{ json: {
  db06_id: p.id.replace(/-/g, ''),
  ai_mode: p.properties['ai模式']?.select?.name || '',
  execute_idea_db06: p.properties['執行構想']?.rich_text?.map(t=>t.plain_text).join('') || '',
  db05_id: (function(){ var T=["對應提案", "對應管考", "對應項目", "對應協作", "對應內容", "對應庫存", "對應對象", "對應標籤", "對應地點", "對應提供對象"]; for(var i=0;i<T.length;i++){var a=p.properties[T[i]]?.relation||[]; if(a.length) return (a[0].id||'').replace(/-/g,'');} return ''; })(),
  target_rel: (function(){ var T=["對應提案", "對應管考", "對應項目", "對應協作", "對應內容", "對應庫存", "對應對象", "對應標籤", "對應地點", "對應提供對象"]; for(var i=0;i<T.length;i++){var a=p.properties[T[i]]?.relation||[]; if(a.length) return T[i];} return ''; })(),
  mingxi_name: p.properties['明細名稱']?.title?.map(t=>t.plain_text).join('') || '',
  sort_num: p.properties['排序']?.number
}}];

const target = $input.first().json;
const item = $('Parse DB06').first().json;
const tprops = target.properties || {};
const target_idea = tprops['執行構想']?.rich_text?.map(t=>t.plain_text).join('') || '';
const _tp = Object.values(tprops).find(v => v && v.type === 'title');
const target_name = (_tp?.title || []).map(t=>t.plain_text).join('') || '';
const target_theme = tprops['主題名稱']?.rich_text?.map(t=>t.plain_text).join('') || '';
const l1 = ((tprops['對應對象']?.relation) || (tprops['對應標籤']?.relation) || (tprops['自對標籤']?.relation) || []).map(r => r.id.replace(/-/g,''));
const base = { ...item, target_idea, target_name, target_theme };
if (l1.length === 0) return [{ json: { ...base, has_l1: false, l1_id: null } }];
return l1.map(id => ({ json: { ...base, has_l1: true, l1_id: id } }));

const l1items = $('Extract Layer1').all();
const layer1 = l1items.map(i => i.json.l1_id).filter(Boolean);
const fetched = $('Fetch DB08').all();
let layer2 = [];
for (const f of fetched) {
  const rel = f.json.properties?.['自對標籤']?.relation || [];
  layer2 = layer2.concat(rel.map(r => r.id.replace(/-/g,'')));
}
const pool = [...new Set([...layer1, ...layer2])];
const base = l1items[0].json;
const db05_or = pool.map(t => ({ property: '對應對象', relation: { contains: t } }));
const db06_or = pool.map(t => ({ property: '對應標籤對象', relation: { contains: t } }));
return [{ json: {
  db06_id: base.db06_id, db05_id: base.db05_id, ai_mode: base.ai_mode, mingxi_name: base.mingxi_name, sort_num: base.sort_num,
  target_idea: base.target_idea, target_name: base.target_name, target_theme: base.target_theme,
  layer1_count: layer1.length, layer2_count: layer2.length, pool_count: pool.length,
  db05_query_body: JSON.stringify({ filter: { or: db05_or }, page_size: 40 }),
  db06_query_body: JSON.stringify({ filter: { or: db06_or }, page_size: 40 })
}}];

const meta = $('Build pool + query').first().json;
const db05r = $('Query DB05').first().json.results || [];
const db06r = $('Query DB06').first().json.results || [];
const target_id = meta.db05_id;
const cands = [];
const seen = new Set();
for (const p of db05r) {
  const id = p.id.replace(/-/g,'');
  if (id === target_id || seen.has(id)) continue;
  seen.add(id);
  const title = p.properties['內容名稱']?.title?.map(t=>t.plain_text).join('') || '(未命名)';
  cands.push({ id, db: 'DB05', x_field: '內容引用', title });
}
for (const p of db06r) {
  const id = p.id.replace(/-/g,'');
  if (seen.has(id)) continue;
  seen.add(id);
  const title = p.properties['明細名稱']?.title?.map(t=>t.plain_text).join('') || '(未命名)';
  cands.push({ id, db: 'DB06', x_field: '明細引用', title });
}
const capped = cands.slice(0, 30);
if (capped.length === 0) {
  return [{ json: { ...meta, has_cand: false, cand_count: 0 } }];
}
return capped.map((c, i) => ({ json: { ...meta, has_cand: true, cand_count: capped.length, c_num: i+1, c_id: c.id, c_db: c.db, c_xfield: c.x_field, c_title: c.title } }));

const cands = $('Collect candidates').all().map(i => i.json);
const meta = cands[0];
const listText = cands.map(c => c.c_num + '. [' + c.c_db + '] ' + c.c_title).join('
');
const system = '你是 makesense 嗨嗨家族的聯想棒判斷層。你的核心能力是跨類資料引用的語意把關。n8n 已用標籤 traversal 撈出一批候選 page,你要逐筆判斷「這筆候選跟 target 內容是否真的相關、值得被引用為參考」,避免無腦把所有共標籤的東西都連進來。

判斷原則:
1. 主題、事件、人物、地點實際相關才留;只是剛好共用一個廣泛標籤但內容無關的,剔除。
2. 寧缺勿濫,只留真正有引用價值的。
3. 回 JSON,最後一個區塊只有 JSON:
{"hits": [命中的候選編號數字], "execution_summary": "判斷了幾筆、留幾筆、剔除原因摘要"}';
const user = 'target 內容
名稱 ' + meta.target_name + '
主題 ' + meta.target_theme + '
執行構想
' + (meta.target_idea || '(空)') + '

候選清單(編號 DB 標題)
' + listText + '

請逐筆判斷哪些候選真的跟 target 相關值得引用,回 JSON。';
return [{ json: { system, user, db06_id: meta.db06_id, db05_id: meta.db05_id, ai_mode: meta.ai_mode, sort_num: meta.sort_num, cand_count: meta.cand_count } }];

const resp = $input.first().json;
const prompt = $('Build judge prompt').first().json;
const cands = $('Collect candidates').all().map(i => i.json);
const usage = resp.usage || {};
const text = resp.content?.[0]?.text || '';
let parsed;
try { const m = text.match(/\{[\s\S]*\}/); parsed = m ? JSON.parse(m[0]) : { hits: [], execution_summary: text.slice(0,300) }; }
catch(e) { parsed = { hits: [], execution_summary: 'JSON parse failed' }; }
const hitNums = Array.isArray(parsed.hits) ? parsed.hits.map(n => parseInt(n)) : [];
const db05_hits = [];
const db06_hits = [];
for (const c of cands) {
  if (!hitNums.includes(c.c_num)) continue;
  if (c.c_xfield === '內容引用') db05_hits.push(c.c_id);
  else if (c.c_xfield === '明細引用') db06_hits.push(c.c_id);
}
const input_tokens = parseInt(usage.input_tokens||0);
const output_tokens = parseInt(usage.output_tokens||0);
const cost_ntd = ((input_tokens*3 + output_tokens*15)/1000000*32).toFixed(2);
const sanitize = s => (s||'').toString().replace(/[\/\\:<>#@\[\]\{\}\|\^\`\*_~"']/g,' ').replace(/[\u2010-\u2027\u2030-\u205E]/g,' ').replace(/[\uFF00-\uFF0F\uFF1A-\uFF20\uFF3B-\uFF40\uFF5B-\uFF65]/g,' ').replace(/[\u3000-\u3017\u301D-\u303F]/g,' ').replace(/\s+/g,' ').trim().slice(0,400);
const summary = '聯想棒 hybrid 完成。候選 ' + cands.length + ' 筆,Claude 判定命中 ' + (db05_hits.length+db06_hits.length) + ' 筆(內容引用 ' + db05_hits.length + ',明細引用 ' + db06_hits.length + ')。' + sanitize(parsed.execution_summary||'');
let props = {};
if (db05_hits.length > 0) props['內容引用'] = { relation: db05_hits.map(id=>({id})) };
if (db06_hits.length > 0) props['明細引用'] = { relation: db06_hits.map(id=>({id})) };
return [{ json: { db06_id: prompt.db06_id, db05_id: prompt.db05_id, ai_mode: prompt.ai_mode, sort_num: prompt.sort_num, hit_count: db05_hits.length+db06_hits.length, summary, target_props: props, has_props: Object.keys(props).length>0, usage_line: '進=' + input_tokens + ' 出=' + output_tokens + ' 成本NT' + cost_ntd } }];

const row = $input.first().json || {};
const pc = $('Merge final').first().json;
const auto_mode = row.auto_mode === true;
const reply_to = parseInt(row.last_msg_id || 0) || 0;
const base = '關卡B 成果確認
第 ' + (pc.sort_num != null ? pc.sort_num : '?') + ' 棒 (' + pc.ai_mode + ') 已完成。
DB06 頁面 ' + pc.db06_id + '

執行備註:
' + (pc.summary + '

寫入 X引用 ' + pc.hit_count + ' 筆。tokens ' + pc.usage_line);
const manual_msg = base + '

按 OK 進下一棒,按 OK ALL 之後全自動。要 redo 重跑請打字 reply。
gateB db06=' + pc.db06_id;
const auto_msg = base + '

[全自動模式] 自動進下一棒,免按。';
return [{ json: { auto_mode, reply_to, flow_id: pc.db05_id, db05_id: pc.db05_id, db06_id: pc.db06_id, sort_num: pc.sort_num, ai_mode: pc.ai_mode, manual_msg, auto_msg, cb_ok: 'B1:' + pc.db06_id, cb_all: 'BA:' + pc.db06_id } }];

